package com.parkflow.mall.gateway;
import com.parkflow.mall.gateway.controller.PaymentGatewayController; import com.parkflow.mall.gateway.payment.PaymentServiceProxy; import org.junit.jupiter.api.Test; import org.springframework.beans.factory.annotation.*; import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest; import org.springframework.boot.test.mock.mockito.MockBean; import org.springframework.http.*; import org.springframework.test.web.servlet.MockMvc; import static org.mockito.ArgumentMatchers.*; import static org.mockito.Mockito.*; import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*; import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;
@WebMvcTest(PaymentGatewayController.class) class PaymentGatewayControllerTests { @Autowired MockMvc mvc; @MockBean PaymentServiceProxy proxy; @Test void reconciliationRoutesForwardHeadersAndFiltersAndInternalRoutesStayHidden() throws Exception { when(proxy.forward(anyString(),any(),any(),any(),any())).thenReturn(ResponseEntity.ok().contentType(MediaType.APPLICATION_JSON).body("{}")); mvc.perform(post("/api/payments/reconciliation/run").header("Authorization","Bearer admin").header("Idempotency-Key","key").contentType(MediaType.APPLICATION_JSON).content("{}")).andExpect(status().isOk()); verify(proxy).forward("/api/payments/reconciliation/run",HttpMethod.POST,"{}","Bearer admin","key"); mvc.perform(get("/api/payments/reconciliation/items").param("status","OPEN").param("paymentOrderId","pay-1").param("targetId","session-1").header("Authorization","Bearer admin")).andExpect(status().isOk()); verify(proxy).forward("/api/payments/reconciliation/items?status=OPEN&paymentOrderId=pay-1&targetId=session-1",HttpMethod.GET,null,"Bearer admin",null); mvc.perform(get("/api/payments/reconciliation/items/item-1").header("Authorization","Bearer admin")).andExpect(status().isOk()); verify(proxy).forward("/api/payments/reconciliation/items/item-1",HttpMethod.GET,null,"Bearer admin",null); mvc.perform(post("/internal/parking/sessions/s/payment-status").content("{}")).andExpect(status().isNotFound()); mvc.perform(post("/internal/parking/sessions/s/discount").content("{}")).andExpect(status().isNotFound()); } }
